const body = $json.body ?? {};
const eventRaw = String(body.event || '').toLowerCase().trim();

// Single-KB Setup
const kb = 'kahleallgemein';

const ROOT_WIN = 'C:\\kahle-vinci\\knowledgebases\\kahleallgemein';
const ROOT_CONTAINER = '/home/node/.n8n-files/knowledgebases/kahleallgemein';

const fullPathWin = body.fullPath ? String(body.fullPath) : null;
const oldFullPathWin = body.oldFullPath ? String(body.oldFullPath) : null;

function normWin(p) {
  return String(p || '')
    .replace(/\//g, '\\')
    .replace(/\\\\+/g, '\\')
    .replace(/\\+$/g, '');
}

function stripPrefixInsensitive(full, prefix) {
  const f = normWin(full);
  const p = normWin(prefix);
  if (!f || !p) return '';
  if (f.toLowerCase().startsWith(p.toLowerCase())) return f.slice(p.length);
  return f;
}

// relPath
const relPathWinRaw = fullPathWin ? stripPrefixInsensitive(fullPathWin, ROOT_WIN) : '';
const relPath = relPathWinRaw.replace(/^\\+/, '').replace(/\\/g, '/');

const containerPath = relPath ? `${ROOT_CONTAINER}/${relPath}` : null;
const doc_id = relPath ? `${kb}/${relPath}` : null;

// old_doc_id bei rename
let old_doc_id = null;
if (oldFullPathWin) {
  const oldRelWinRaw = stripPrefixInsensitive(oldFullPathWin, ROOT_WIN);
  const oldRelPath = oldRelWinRaw.replace(/^\\+/, '').replace(/\\/g, '/');
  old_doc_id = oldRelPath ? `${kb}/${oldRelPath}` : null;
}

// delete_doc_id (was soll gelöscht werden?)
let delete_doc_id = '';
if (eventRaw === 'deleted' || eventRaw === 'changed') delete_doc_id = doc_id || '';
if (eventRaw === 'renamed') delete_doc_id = old_doc_id || '';

// Qdrant filter (dein Payload hat metadata.doc_id)
const delete_filter = delete_doc_id
  ? { must: [{ key: 'metadata.doc_id', match: { value: delete_doc_id } }] }
  : null;

// Optional: Input-Debug (zeigt dir, ob vorher schon was reinkam)
const in_delete_doc_id = $json.delete_doc_id ?? null;
const in_delete_filter = $json.delete_filter ?? null;

return [{
  json: {
    event: eventRaw,
    kb,
    fullPathWin,
    oldFullPathWin,
    relPathWin: relPathWinRaw,
    relPath,
    containerPath,
    doc_id,
    old_doc_id,
    delete_doc_id,
    delete_filter,
    ts: body.ts || new Date().toISOString(),

    // Debug: Input vs Output sauber getrennt
    debug_in_delete_doc_id: in_delete_doc_id,
    debug_in_delete_filter_type: typeof in_delete_filter,

    debug_out_delete_doc_id: delete_doc_id || null,
    debug_out_delete_filter_type: typeof delete_filter,
    debug_out_delete_filter_isArray: Array.isArray(delete_filter),
    debug_out_delete_filter_hasMust: !!(delete_filter && delete_filter.must),

    // hilfreich zum schnellen Sichtcheck im UI
    debug_out_delete_filter_json: delete_filter ? JSON.stringify(delete_filter) : null,
  }
}];

// Erwartet Response vom Ollama Embeddings Endpoint: { embedding: [..] }
const emb = $json.embedding;
const vector_size = Array.isArray(emb) ? emb.length : 0;

return [{ vector_size }];

// Guard: nur weiter, wenn Read/Write Files from Disk wirklich Binary geliefert hat
const items = $input.all();

return items.filter((item) => {
  // Standardfeld aus Read/Write Files from Disk: binary.data (Options -> dataPropertyName: "data")
  const hasBinary = !!(item.binary && item.binary.data);

  // Optional: zusätzlich sicherstellen, dass Metadaten da sind
  const hasMeta = !!(item.json && item.json.doc_id && item.json.kb);

  return hasBinary && hasMeta;
});

