/**
 * WF B — Code in JavaScript1
 * Zweck: cfg + query übernehmen, Embedding-Vektor als sauberes number[] ausgeben (optional normalisiert)
 */
function toFloatArray(vec) {
  if (!vec) return [];
  if (Array.isArray(vec)) return vec.map((x) => Number(x));
  // falls es als Objekt { "0": 0.1, "1": 0.2, ... } kommt:
  return Object.values(vec).map((x) => Number(x));
}

function l2Normalize(vec) {
  const norm = Math.sqrt(vec.reduce((acc, v) => acc + v * v, 0));
  if (!Number.isFinite(norm) || norm === 0) return vec;
  return vec.map((v) => v / norm);
}

const inp = $input.first().json;

// cfg + query kommen typischerweise aus Edit Fields / Merge
const cfg = inp.cfg || {};
const query = inp.query || "";

// Embeddings kommen aus deiner Ollama-Embed HTTP Node (bei dir heißt sie "HTTP Request")
const embedResp = $node["HTTP Request"].json || {};
const rawEmbeddings = embedResp.embeddings ?? embedResp.embedding ?? [];

// Ollama liefert meistens embeddings: [ [..768..] ]
const rawVec = Array.isArray(rawEmbeddings) ? rawEmbeddings[0] : rawEmbeddings;

let embeddingVector = toFloatArray(rawVec);

// OPTIONAL: Bei Cosine in Qdrant oft sinnvoll
embeddingVector = l2Normalize(embeddingVector);

// Sanity checks
if (!Array.isArray(embeddingVector) || embeddingVector.length === 0) {
  return [{ json: { ...inp, cfg, query, embeddingVector: [] } }];
}
if (embeddingVector.some((v) => !Number.isFinite(v))) {
  embeddingVector = embeddingVector.map((v) => (Number.isFinite(v) ? v : 0));
