  // Fallback: wenigstens die aktuelle Pipeline nicht hart crashen lassen
  return [{ json: { ...base, collection: base?.cfg?.defaultCollection || "kahlerichtlinien" } }];
}

return cols.map((c) => ({
  json: {
    ...base,
    collection: String(c),
  },
}));

