parameters.jsCode:
// Build retrieval (multi)
// Input: mehrere Items (je Collection ein HTTP-Response von Qdrant Search)
// Output: ein Item mit retrieval { routedCollections, results, stats, didFallbackAll }

const items = $input.all();

// Helper: Qdrant HTTP node kann entweder {result:...} direkt liefern
// oder {body:{result:...}} wenn "Include Response Headers and Status" aktiv ist.
function getBody(j) {
  return j && typeof j === "object" && j.body && typeof j.body === "object" ? j.body : j;
}

const routedCollections = [];
const allHits = [];
const errors = [];

for (const it of items) {
  const j = it.json || {};
  const body = getBody(j);

  const collection = j.collection || j.kb || body.kb || body.collection;
  if (collection) routedCollections.push(String(collection));

  // Fehlerfälle einsammeln, aber nicht crashen
  if (j.error || body?.status === "error" || body?.result?.status === "error") {
    errors.push({
      collection: collection || "unknown",
      error: j.error || body?.result || body,
    });
    continue;
  }

  // Qdrant search: body.result ist meist Array von Punkten
  let resultArr = [];
  if (Array.isArray(body?.result)) resultArr = body.result;
  else if (Array.isArray(body?.result?.points)) resultArr = body.result.points;
  else if (Array.isArray(body?.points)) resultArr = body.points;

  for (const p of resultArr) {
    const payload = p?.payload || {};
    const text =
      payload.content ??
      payload.text ??
      payload.page_content ??
      payload.chunk ??
      "";

    const doc_id =
      payload.doc_id ??
      payload.document_id ??
      payload.source_path ??
      payload.source ??
      "";

    const source_path = payload.source_path ?? payload.sourcePath ?? "";
    const loc = payload.loc ?? payload.location ?? payload.metadata?.loc ?? {};

    allHits.push({
      id: String(p?.id ?? ""),
      chunk_id: String(p?.id ?? ""),
      score: Number(p?.score ?? 0),
      text: String(text),
      kb: String(collection || payload.kb || ""),
      doc_id: String(doc_id || ""),
      source_path: String(source_path || ""),
      loc: loc && typeof loc === "object" ? loc : {},
      metadata: payload.metadata ?? payload.meta ?? {},
      cite: `${collection || payload.kb || "unknown"}/${doc_id || "unknown"}/${p?.id ?? "unknown"}`,
    });
  }
}

// sort by score desc
allHits.sort((a, b) => (b.score ?? 0) - (a.score ?? 0));

// optional thresholds/max chunks aus cfg nehmen (wenn vorhanden)
const cfg = items[0]?.json?.cfg || {};
const scoreThreshold = typeof cfg.scoreThresholdRetrieval === "number" ? cfg.scoreThresholdRetrieval : null;
const maxFinal = typeof cfg.maxFinalChunks === "number" ? cfg.maxFinalChunks : null;

let finalHits = allHits;
if (scoreThreshold !== null) {
  finalHits = finalHits.filter((h) => h.score >= scoreThreshold);
}
if (maxFinal !== null) {
  finalHits = finalHits.slice(0, maxFinal);
}

const uniqRouted = [...new Set(routedCollections.filter(Boolean))];

const retrieval = {
  routedCollections: uniqRouted,
  didFallbackAll: false,
  results: finalHits,
  stats: {
    top1_score: finalHits.length ? finalHits[0].score : 0,
    count_first: allHits.length,
    count_fallback: 0,
    count_final: finalHits.length,
    errors_count: errors.length,
  },
  debug: errors.length ? { errors } : undefined,
};

return [{ json: { retrieval } }];

/**
 * WF C — Code in JavaScript (Prompt Builder)
 * Input erwartet:
 * {
 *   query: string,
 *   retrieval: object | string(JSON)
 * }
 */

const inp = $input.first()?.json ?? {};

const query = String(inp.query ?? inp.chatInput ?? inp.text ?? inp.message ?? '').trim();

// --- retrieval robust holen (Object oder String(JSON)) ---
let retrieval = inp.retrieval ?? {};
if (typeof retrieval === 'string') {
  try {
    retrieval = JSON.parse(retrieval);
  } catch (e) {
    retrieval = {};
  }
}

// manchmal kommt es verschachtelt: { retrieval: { results... } }
if (retrieval?.retrieval && !retrieval?.results) {
  retrieval = retrieval.retrieval;
}

const resultsRaw = Array.isArray(retrieval?.results) ? retrieval.results : [];

// Normalize + sort
const results = resultsRaw
  .map((r) => ({
    ...r,
    score: Number(r?.score ?? 0),
  }))
  .sort((a, b) => b.score - a.score);

const computedTop1 = results.length ? results[0].score : 0;
const top1 = Number(retrieval?.stats?.top1_score ?? computedTop1);

// Harte Gate-Regeln (Halluzinationsschutz)
const ANSWER_THRESHOLD = 0.45;

if (!query) {
  return [{
    json: {
      decision: 'NOT_IN_KNOWLEDGE',
      answerText: 'Nicht im Wissen.',
      prompt: null,
      debug: { reason: 'empty_query' }
    }
  }];
}

if (results.length === 0 || !(top1 >= ANSWER_THRESHOLD)) {
  return [{
    json: {
      decision: 'NOT_IN_KNOWLEDGE',
      answerText: 'Nicht im Wissen.',
      prompt: null,
      debug: {
        reason: 'insufficient_retrieval',
        top1_score: top1,
        results_count: results.length
      }
    }
  }];
}

// Helper: Text begrenzen (Prompt-Budget)
function clip(str, maxChars) {
  const s = String(str ?? '');
  if (s.length <= maxChars) return s;
  return s.slice(0, maxChars) + '…';
}

// Für Cite: collection muss regex-freundlich sein (dein Validator erwartet [a-z0-9_-]+ als collection)
function normCollection(v) {
  const s = String(v ?? 'unknown_collection').toLowerCase();
  const cleaned = s.replace(/[^a-z0-9_-]+/g, '_').replace(/_+/g, '_').replace(/^_+|_+$/g, '');
  return cleaned || 'unknown_collection';
}

function basename(v) {
  if (!v) return '';
  return String(v).split('/').pop();
}

function normToken(v, fallback) {
  const s = String(v ?? fallback ?? '').replace(/[\[\]\r\n]/g, ' ').trim();
  return s || String(fallback ?? 'unknown');
}

// SOURCES Block bauen (Cite immer exakt [collection/doc_id/chunk_id])
const maxFinalChunks = 8;
const sourcesBlock = results.slice(0, maxFinalChunks).map((s, i) => {
  const collection = normCollection(s.collection ?? s.kb ?? 'unknown_collection');

  const docIdRaw = s.doc_id ?? s.source_path ?? s.source_file ?? 'unknown_doc';
  const docId = normToken(basename(docIdRaw) || docIdRaw, 'unknown_doc');

  const chunkIdRaw = s.chunk_id ?? s.id ?? `hit_${i + 1}`;
  const chunkId = normToken(basename(chunkIdRaw) || chunkIdRaw, `hit_${i + 1}`);

  const cite = `[${collection}/${docId}/${chunkId}]`;

  const file = s.source_path ?? s.source_file ?? 'n/a';
  const locFrom = s?.loc?.lines?.from ?? 'n/a';
  const locTo = s?.loc?.lines?.to ?? 'n/a';

  const metaLine =
    `meta: collection=${collection}, doc_id=${docId}, chunk_id=${chunkId}, ` +
    `file=${file}, lines=${locFrom}-${locTo}, score=${s.score}`;

  const text = clip(s.text ?? '', 1200);

  return `SOURCE ${i + 1}: ${cite}\n${metaLine}\n${text}`;
}).join('\n\n---\n\n');

// System Prompt
const system =
`Du bist ein Unternehmens-assistierendes System. Du darfst ausschließlich Aussagen machen, die direkt durch die SOURCES belegt sind.

Regeln:
1) Jede Aussage muss mindestens eine Quellenangabe im Format [collection/doc_id/chunk_id] enthalten (am Satzende).
2) Wenn die SOURCES nicht ausreichen, antworte exakt: "Nicht im Wissen."
3) Keine Vermutungen, keine externen Fakten, keine Ergänzungen aus Vorwissen.
4) Antworte auf Deutsch, präzise und strukturiert.`;

// User Prompt
const user =
`SOURCES:
${sourcesBlock}

USER QUESTION:
${query}

AUFGABE:
Beantworte die Frage ausschließlich mit Informationen aus den SOURCES.
Jede Aussage muss Quellenangaben [collection/doc_id/chunk_id] direkt am Satzende enthalten.
Wenn nicht ausreichend belegt: antworte exakt "Nicht im Wissen."`;

return [{
  json: {
    decision: 'ANSWER',
    system,
    user,
    debug: {
      top1_score: top1,
      results_count: results.length
    }
  }
}];

const inp = $input.first().json;
const text = inp?.message?.content || inp?.response?.message?.content || '';

// require at least one citation token like [kahleallgemein/XYZ/ABC]
const hasCite = /\[[a-z0-9_-]+\/[^\/\]]+\/[^\/\]]+\]/i.test(text);

if (!hasCite) {
  return [{ json: {
    decision: 'NOT_IN_KNOWLEDGE',
    answerText: 'Nicht im Wissen.'
  }}];
}

return [{ json: { decision: 'ANSWER', answerText: text } }];

