={{ (() => {
  // n8n Webhook legt Body meistens unter $json.body ab – Chat-Trigger meist direkt auf root
  const root = $json ?? {};
  const b = root.body ?? root;

  // 1) n8n Chat Trigger
  if (typeof b.chatInput === "string" && b.chatInput.trim()) {
    return b.chatInput.trim();
  }

  // 2) Webhook-Variante: query Feld
  if (typeof b.query === "string" && b.query.trim()) {
    return b.query.trim();
  }

  // 3) OpenWebUI: messages[] -> letzte User-Nachricht nehmen
  const msgs = b.messages ?? root.messages;
  if (Array.isArray(msgs)) {
    for (let i = msgs.length - 1; i >= 0; i--) {
      const m = msgs[i] || {};
      const role = m.role ?? m.type;
      const content = m.content ?? m.text;
      if ((role === "user" || !role) && typeof content === "string" && content.trim()) {
        return content.trim();
      }
    }
  }

  // 4) Fallback: prompt (manche Integrationen)
  if (typeof b.prompt === "string" && b.prompt.trim()) {
    return b.prompt.trim();
  }

  return "";
})() }}

parameters.jsCode:
const r = $json.retrieval ?? {};
const threshold = 0.45;

const results = Array.isArray(r.results) ? r.results : [];

// Dedupe (weil du oft doppelte Chunks bekommst)
const seen = new Set();
const chunks = [];

for (const it of results) {
  const chunkId = it.chunk_id || it.id;
  if (!chunkId || seen.has(chunkId)) continue;
  seen.add(chunkId);

  chunks.push({
    n: chunks.length + 1,
    collection: it.kb || it.collection || "unknown",
    doc_id: it.doc_id || it.source_path || "",
    chunk_id: chunkId,
    score: typeof it.score === "number" ? it.score : null,
    cite: it.cite || "",
    text: (it.text || "").slice(0, 1500),
  });

  if (chunks.length >= 4) break;
}

const top1 = chunks.length && typeof chunks[0].score === "number" ? chunks[0].score : 0;
const found = top1 >= threshold && chunks.length > 0;

const context = chunks
  .map(c => `[#${c.n} | ${c.collection} | score ${c.score}] ${c.text}`)
  .join("\n\n");

return [{
  json: {
    query: $json.query || "",
    found,
    top1_score: top1,
    answer_threshold: threshold,
    routedCollections: r.routedCollections || [],
    chunks,
    context,
  }
}];

