// Original Query (nicht in Response ausgeben)
const originalQuery = $node["Init Request"].json.query ?? "";

// Guardrails Output: n8n Guardrails schreibt Sanitizing bei dir in `guardrailsInput`
const sanitizedTextRaw =
  ($json.sanitizedText ?? $json.guardrailsInput ?? originalQuery).toString();

// Zusätzlich: Ausgabe-Text für Notice (mit Platzhaltern), aber ohne Original-PII
const noticeQueryRaw = (sanitizedTextRaw || $json.guardrailsInput || "").toString().trim();

// für UI/Logs begrenzen (optional, aber empfohlen)
const noticeQuery = noticeQueryRaw.length > 500
  ? noticeQueryRaw.slice(0, 499) + "…"
  : noticeQueryRaw;

// Checks
const checks = Array.isArray($json.checks) ? $json.checks : [];
const triggeredChecks = checks
  .filter(c => c && (c.triggered === true || c.triggered === 'true'))
  .map(c => c.name);

// Analyzer entityTypes (wenn vorhanden)
const analyzerResults = checks.flatMap(c => (c?.info?.analyzerResults ?? []));
const analyzerEntityTypes = analyzerResults.map(r => r?.entityType).filter(Boolean);

// Placeholder Types aus Sanitizing (z.B. <IBAN>, <LICENSE_PLATE_DE>, ...)
const placeholderTypes = Array.from(
  new Set(
    [...sanitizedTextRaw.matchAll(/<([A-Z0-9_]+)>/g)].map(m => m[1])
  )
);

// Secrets
const detectedSecrets = checks.flatMap(c => (c?.info?.detectedSecrets ?? []));
const hasSecrets = triggeredChecks.includes('secretKeys') || detectedSecrets.length > 0;

// High-Risk analyzer entity types
// ✅ Wichtig: LICENSE_PLATE_* hier aufnehmen, sonst bleibt hasHighRiskEntities bei Kennzeichen false
const HIGH_RISK_ENTITY_TYPES = new Set([
  'US_BANK_NUMBER',
  'IBAN',
  'IBAN_CODE',
  'CREDIT_CARD',
  'CREDIT_CARD_NUMBER',
  'BANK_ACCOUNT',
  'TAX_ID',
  'SSN',
  'PASSPORT',
  'DRIVER_LICENSE',
  'LICENSE_PLATE_DE',
  'LICENSE_PLATE_DE_GOV',
  'LICENSE_PLATE_EU',
]);

const hasHighRiskEntities =
  analyzerEntityTypes.some(t => HIGH_RISK_ENTITY_TYPES.has(t) || String(t).startsWith('IBAN'));

// High-/Medium-Risk über Placeholders (Custom Regex)
const HIGH_RISK_PLACEHOLDERS = new Set([
  'FIN',
  'LICENSE_PLATE_DE',
  'LICENSE_PLATE_DE_GOV',
  'LICENSE_PLATE_EU',
  'IBAN',
  'IBAN_DE',
  'CREDIT_CARD',
  'BANK_ACCOUNT',
  'SECRET',
  'API_KEY',
  'TOKEN'
]);

const MEDIUM_RISK_PLACEHOLDERS = new Set([
  'CUSTOMER_ID',
  'PERSON_DE',
  'ADDRESS_DE',
  'PHONE_INTL',
  'LOCATION_DE'
]);

const hasHighRiskCustomRegex = placeholderTypes.some(p => HIGH_RISK_PLACEHOLDERS.has(p));
const hasMediumRiskCustomRegex = placeholderTypes.some(p => MEDIUM_RISK_PLACEHOLDERS.has(p));

// Suchquery: Placeholders entfernen, damit Websuche nicht mit "<...>" läuft
const searchQuery = sanitizedTextRaw
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

// Redaction/Unusable
const redacted =
  sanitizedTextRaw.trim() !== originalQuery.toString().trim() || placeholderTypes.length > 0;

const unusable = searchQuery.length < 8;

// --- Low-signal / Intent-Heuristik (DE) ---
const STOPWORDS_DE = new Set([
  'wenn','dann','mit','aus','der','die','das','den','dem','des','ein','eine','einer','einem','einen',
  'und','oder','aber','zu','zum','zur','von','im','in','am','an','auf','für','bitte','mal','noch',
  'ich','du','er','sie','es','wir','ihr','mir','mich','dir','dich','uns','euch',

  // Fragewörter
  'was','wer','wen','wem','wessen','wie','wo','wann','warum','wieso','weshalb','welche','welcher','welches',
  'wieviel','wieviele','viele','viel',

  // Hilfs-/Allgemeinverben
  'ist','sind','war','waren','sein','bin','bist','seid','hat','haben','habe','hast','gibt','geben',
]);

const lower = searchQuery.toLowerCase();
const tokens = (lower.match(/[a-zäöüß0-9]+/g) ?? []).filter(t => t.length >= 2);

// Meta-/Generic-Wörter (tragen selten Spezifität)
const GENERIC_WORDS = new Set([
  'info','infos','information','informationen','detail','details','sache','sachen','ding','dinge',
  'thema','themen','begriff','begriffe','konzept','konzepte',
  'liste','listen','übersicht','uebersicht','beispiele','beispiel',
  'kategorie','kategorien','allgemein','generell','spezifisch','präzisieren','praezisieren','möglich','moeglich',
  'anzahl','gesamtzahl',
  'suche','suchen','finde','finden','googeln','recherchieren','recherche',
]);

const contentWords = Array.from(new Set(
  tokens
    .filter(w => w.length >= 3 && !STOPWORDS_DE.has(w))
    .filter(w => !GENERIC_WORDS.has(w))
));

const contentCount = contentWords.length;

const placeholderHits = (sanitizedTextRaw.match(/<[^>]+>/g) ?? []).length;
const placeholderDensity = placeholderHits / Math.max(1, placeholderHits + tokens.length);

const hasDemonstrative =
  /\b(das|dies|diese|dieses|so|hier|dort|daran|darüber|dazu|dafür)\b/i.test(searchQuery);

const isCountQuestion =
  /\bwie\s+viele\b/i.test(searchQuery) || /\banzahl\b/i.test(searchQuery);

const properNounCandidates = (originalQuery.match(/\b[A-ZÄÖÜ][a-zäöüß]{2,}\b/g) ?? [])
  .filter(w => !['Ich','Wie','Was','Wer','Wo','Wann','Warum','Wieso','Bitte','Suche','Finde','Infos','Informationen'].includes(w));
const hasProperNoun = properNounCandidates.length > 0;

const hasDigits = /\d/.test(searchQuery);
const hasYear = /\b(19|20)\d{2}\b/.test(searchQuery);

// Spezifitäts-Score
let specificityScore = 0;
if (contentCount >= 4) specificityScore += 3;
else if (contentCount === 3) specificityScore += 2;
else if (contentCount === 2) specificityScore += 1;

if (hasProperNoun) specificityScore += 1;
if (hasYear || hasDigits) specificityScore += 1;

if (hasDemonstrative && contentCount < 2) specificityScore -= 2;
if (isCountQuestion && contentCount < 2) specificityScore -= 2;

if (tokens.length <= 3 && contentCount < 2) specificityScore -= 2;
if (tokens.length <= 5 && contentCount === 0) specificityScore -= 2;

const isLowSpecificity =
  specificityScore <= 0 ||
  (contentCount < 2 && (hasDemonstrative || isCountQuestion)) ||
  (contentCount === 0 && tokens.length <= 6);

// --- Needs Clarification: vage / mehrdeutig ---
const VAGUE_MARKERS = /\b(dafür|dazu|damit|das|dies|so etwas|irgendwas|etwas|darin|daran)\b/i;
const GENERIC_NOUN = /\b(angebot|deal|preis|option|lösung|infos?|information(en)?|details|vergleich|empfehlung(en)?)\b/i;

const isVeryVague =
  (VAGUE_MARKERS.test(searchQuery) && GENERIC_NOUN.test(searchQuery)) ||
  (/^suche\s+mir\b/i.test(searchQuery) && VAGUE_MARKERS.test(searchQuery)) ||
  (/^finde\s+mir\b/i.test(searchQuery) && VAGUE_MARKERS.test(searchQuery)) ||
  (contentCount < 3 && GENERIC_NOUN.test(searchQuery));

const isAmbiguousApple =
  /\bapple\b/i.test(searchQuery) &&
  !/\b(iphone|ipad|mac|macbook|imac|ios|macos|airpods|watch|apfel|obst|frucht|rezept|nährwert)\b/i.test(searchQuery);

// --- Input-Risiko: offensiv vs defensiv ---
const DEFENSIVE_CTX =
  /\b(erkenn\w*|schutz\w*|prävention\w*|praevention\w*|verhind\w*|abwehr\w*|sicher\w*|mitigation\w*|hardening\w*|härt\w*|haert\w*|best\s*practices\w*|warnzeichen\w*|was\s+tun\s+wenn|melden\w*|anzeig\w*|rechtlich\w*|legal\w*|aufklär\w*|aufklaer\w*|einordn\w*|analys\w*|wissenschaft\w*|studie\w*|forschung\w*|deradikalisier\w*|ausstieg\w*)\b/i;

const EXFILTRATION =
  /\b(api[- ]?key|apikey|token|passwort|password|secret|umgebungsvariablen|env\b|logs?\b|systemprompt|developer message|n8n_encryption_key)\b/i;
const EXFILTRATION_VERB =
  /\b(gib|zeige|liste|extrahier|lies|auslesen|leak|dump)\b/i;

const CSAM =
  /\b(kinderporno|kinderpornografie|kinderpornografisch|jugendpornografie|csam|child sexual abuse material|child porn)\b/i;

const HATE_VIOLENCE =
  /\b(töten|umbringen|vernichten|ausrotten|vergase(n)?|abschlachten)\b.*\b(juden|muslime|christen|schwule|lesben|trans|ausländer|flüchtlinge|roma|sinti)\b/i;

const EXTREMISM_GROUP =
  /\b(isis|isil|islamischer\s+staat|daesh)\b/i;

const EXTREMISM_PROPAGANDA =
  /\b(propoganda\w*|propaganda\w*|argument\w*|slogan\w*|überzeug\w*|rekrutier\w*|beitret\w*|join\w*|manifest\w*|verherrlich\w*|glorifizier\w*|unterstütz\w*|werb\w*|video[- ]?script\w*|flyer\w*|poster\w*)\b/i;

const DRUGS =
  /\b(mdma|ecstasy|meth|crystal|kokain|heroin|lsd|amphetamin|dmt)\b/i;
const DRUG_HOWTO =
  /\b(wie\s+(stelle|mache|koche|mische)\s+ich|stell(e)?\s+ich.*\s+her|herstellen|synthe(se|sieren)|rezept|anleitung|schritt[- ]für[- ]schritt)\b/i;

const WEAPONS =
  /\b(bombe|sprengsatz|sprengstoff|molotow|rohrbombe|waffe(n)? bauen|munition herstellen|schalldämpfer)\b/i;
const WEAPONS_HOWTO =
  /\b(wie\s+(baue|mache|konstruiere)\s+ich|anleitung|schritt[- ]für[- ]schritt|herstellen)\b/i;

const CYBER =
  /\b(sql[- ]?injection|xss|rce|exploit|payload|malware|ransomware|keylogger|phishing|ddos|botnet)\b/i;
const CYBER_OFFENSIVE =
  /\b(umgehen|bypass|admin[- ]?login|passwort knacken|credential stuffing|payload|exploit)\b/i;

const FRAUD =
  /\b(betrug|scam|carding|kreditkarte(n)? fälschen|fake id|ausweis fälschen|kontoübernahme)\b/i;
const FRAUD_DEFENSIVE =
  /\b(woran erkenne|wie erkenne|prüfen|echtheit|was mache ich wenn|was tun wenn|melden|anzeige)\b/i;

// Entscheidung
let decision = 'proceed';
let notice = '';

// 1) Illegale/gefährliche Intents
const exfiltrationAttempt =
  EXFILTRATION.test(searchQuery) && EXFILTRATION_VERB.test(searchQuery) && !DEFENSIVE_CTX.test(searchQuery);

const csamAttempt = CSAM.test(searchQuery);
const hateViolenceAttempt = HATE_VIOLENCE.test(searchQuery);

const extremismPropagandaAttempt =
  EXTREMISM_GROUP.test(searchQuery) && EXTREMISM_PROPAGANDA.test(searchQuery) && !DEFENSIVE_CTX.test(searchQuery);

const drugHowToAttempt =
  DRUGS.test(searchQuery) && DRUG_HOWTO.test(searchQuery) && !DEFENSIVE_CTX.test(searchQuery);

const weaponsHowToAttempt =
  WEAPONS.test(searchQuery) && WEAPONS_HOWTO.test(searchQuery) && !DEFENSIVE_CTX.test(searchQuery);

const cyberOffensiveAttempt =
  CYBER.test(searchQuery) && (CYBER_OFFENSIVE.test(searchQuery) || /\banleitung|payload|exploit\b/i.test(searchQuery)) && !DEFENSIVE_CTX.test(searchQuery);

const fraudAttempt =
  FRAUD.test(searchQuery) && !FRAUD_DEFENSIVE.test(searchQuery) && !DEFENSIVE_CTX.test(searchQuery);

const illegalOrHarmfulAttempt =
  exfiltrationAttempt || csamAttempt || hateViolenceAttempt ||
  extremismPropagandaAttempt || drugHowToAttempt || weaponsHowToAttempt ||
  cyberOffensiveAttempt || fraudAttempt;

// ✅ 2) Sensitive High-Risk PII/Secrets: soll in deinen "High-Risk" Branch
const sensitiveHighRiskDetected = hasSecrets || hasHighRiskEntities || hasHighRiskCustomRegex;

if (illegalOrHarmfulAttempt) {
  decision = 'block_high_risk';
  notice =
    `Ich kann bei dieser Anfrage nicht helfen, da sie Exfiltration, illegale Inhalte oder gefährliche/kriminelle Handlungen betrifft. Formuliere defensiv/neutral. - Bereinigte Anfrage: "${noticeQuery}"`;

} else if (sensitiveHighRiskDetected) {
  // ✅ FIX: nicht mehr needs_clarification -> sondern block_high_risk
  decision = 'block_high_risk';
  notice =
    `Ich kann die Websuche nicht ausführen, weil sensible Daten/Identifier erkannt wurden (z. B. Kennzeichen, IBAN, Kreditkarte, Token/API-Key). Bitte entferne diese Daten und stelle die Frage erneut – ohne Codes/IDs. - Bereinigte Anfrage: "${noticeQuery}"`;

} else if (
  unusable ||
  isLowSpecificity ||
  isVeryVague ||
  isAmbiguousApple ||
  (redacted && (contentCount < 2 || placeholderDensity >= 0.35))
) {
  decision = 'needs_clarification';
  notice =
    `Bitte präzisiere deine Anfrage (Thema, Ziel, Region/Zeitraum, Constraints). Beispiel: „VW ID.4: Leasingangebote DE, 24 Monate, 10.000 km/Jahr, 0 € Anzahlung, max. 350 €/Monat“. - Bereinigte Anfrage: "${noticeQuery}"`;

} else if (redacted || hasMediumRiskCustomRegex) {
  decision = 'proceed';
  notice =
    'Ich habe personenbezogene oder interne Daten aus der Anfrage entfernt/anonymisiert und führe die Websuche mit der bereinigten Anfrage aus. - Bereinigte Anfrage: "${noticeQuery}"';
}

return [{
  json: {
    ...$json,
    searchQuery,
    policy: {
      decision,
      redacted,
      notice,
      triggeredChecks,
      triggeredPatterns: placeholderTypes,
      triggeredEntityTypes: Array.from(new Set(analyzerEntityTypes)),
      debug: {
        illegalOrHarmfulAttempt,
        sensitiveHighRiskDetected,
        hasSecrets,
        hasHighRiskEntities,
        hasHighRiskCustomRegex,
        tokensCount: tokens.length,
        contentCount,
        specificityScore,
      }
    }
  }
}];

// Fast Output Gate (v2) — robust topic detection + routing to Output Gate (LLM)
// Goals:
// - Detect safety-relevant topics reliably (prompt injection, exfiltration, cyber, extremism, etc.)
// - Route ANY non-PII topic detection to Output Gate via needsLLMGate=true
// - PII-only: redact + respond via webhook (no Output Gate trigger)

const searchQuery = ($json.searchQuery ?? $json.query ?? "").toString();
const summary = ($json.summary ?? "").toString();
const sources = Array.isArray($json.sources) ? $json.sources : [];

const sourcesText = sources
  .map(s => `${s.title ?? ""}\n${s.snippet ?? ""}\n${s.url ?? ""}`)
  .join("\n");

// Intent nur aus Query+Summary (wichtig: defensive Prompts nicht durch Snippets killen)
const intentText = `${searchQuery}\n${summary}`.slice(0, 14000);

// Fallback: wenn summary quasi leer ist (z.B. Tests), dann scannen wir ein kleines Stück sources
const sourceFallback = summary.trim().length < 30 ? sourcesText.slice(0, 6000) : "";
const detectText = `${intentText}\n${sourceFallback}`.slice(0, 20000);

// Für PII lieber das volle Material prüfen (kann in Snippets stecken)
const fullText = `${intentText}\n${sourcesText}`.slice(0, 24000);

const triggered = [];
const add = (k, ok) => { if (ok) triggered.push(k); };

// ✅ Defensive Kontext (DE+EN, inkl. Komposita/Flexionen)
// Wird NICHT mehr verwendet, um Prompt-Injection *Topic* zu unterdrücken.
// (Nur optional, um "Attacke" vs "Diskussion" zu unterscheiden.)
const DEFENSIVE_CTX =
  /\b(erkenn\w*|schutz\w*|prävention\w*|praevention\w*|verhind\w*|abwehr\w*|sicher\w*|mitigation\w*|hardening\w*|härt\w*|haert\w*|best\s*practices?\w*|warnzeichen\w*|was\s+tun\s+wenn|melden\w*|anzeig\w*|rechtlich\w*|legal\w*|aufklär\w*|aufklaer\w*|einordn\w*|analys\w*|wissenschaft\w*|studie\w*|forschung\w*|deradikalisier\w*|ausstieg\w*|counter\w*|defens\w*|prevent\w*|mitigate\w*|awareness\w*)\b/i;

// --- Prompt Injection (DE+EN) ---
// Keywords (Topic)
const PROMPT_INJECTION =
  /\b(prompt[- ]?injection|jailbreak|dan\b|do anything now|developer mode|system mode|dev mode)\b/i;

// Phrasen / Muster (Topic) — inkl. Tippfehler "previos"
const PROMPT_INJECTION_PHRASES =
  /\b(ignore|disregard|bypass|override|forget)\b.{0,50}\b(instructions?|rules?|polic(y|ies)|previous|previo\w*|prior|earlier)\b|\b(you are now|from now on)\b.{0,50}\b(system|developer|admin)\b|\b(act(?:ing)?\s+as)\b.{0,50}\b(system|developer|admin)\b|\b(rolle:\s*system|rolle\s*=\s*system|role:\s*system)\b/i;

// Attack-Verb (direktive Aufforderung)
const PI_ATTACK_VERBS =
  /\b(respond as|answer as|act(?:ing)? as|from now on|you are now|ignore|disregard|override|bypass|forget|rolle:\s*system|role:\s*system)\b/i;

// Topic vs Attack
const PI_TOPIC =
  PROMPT_INJECTION.test(detectText) ||
  PROMPT_INJECTION_PHRASES.test(detectText) ||
  /\b(ignorier(e|en)?|prompt[- ]?injection|jailbreak|dan)\b/i.test(detectText);

// Attack: nur wenn es im Intent (Query+Summary) wie eine direkte Instruktion aussieht
const PI_ATTACK =
  (PROMPT_INJECTION.test(intentText) || PROMPT_INJECTION_PHRASES.test(intentText)) &&
  PI_ATTACK_VERBS.test(intentText) &&
  !DEFENSIVE_CTX.test(intentText); // defensiv im Intent => eher Diskussion als Attack

// ✅ Trigger: immer wenn Topic ODER Attack erkannt (damit Output Gate übernehmen kann)
add("prompt_injection", PI_TOPIC || PI_ATTACK);

// --- Exfiltration / Secrets (DE+EN) ---
const EXFIL_KW =
  /\b(system\s*prompt|developer\s*message(s)?|hidden\s*(prompt|instructions)|internal\s*(prompt|instructions)|n8n_encryption_key|api[- ]?key|apikey|access\s*token|refresh\s*token|bearer\s*token|secret|password|passwort|credential(s)?|cookie(s)?|session|env(?:ironment)?\s*variables?|umgebungsvariablen|private\s*key)\b/i;

const EXFIL_VERB =
  /\b(show|print|reveal|leak|dump|extract|read|display|output|list|give|provide|gib|zeige|liste|extrahier|lies|auslesen)\b/i;

// Exfil Topic (schon wenn Keywords vorkommen)
const EXFIL_TOPIC = EXFIL_KW.test(detectText);

// Exfil Attempt (keywords + verb + nicht defensiv)
const EXFIL_ATTEMPT = EXFIL_KW.test(intentText) && EXFIL_VERB.test(intentText) && !DEFENSIVE_CTX.test(intentText);

add("exfiltration", EXFIL_TOPIC || EXFIL_ATTEMPT);

// --- Extremismus ---
const EXTREMISM_GROUP = /\b(isis|isil|islamischer\s+staat|daesh)\b/i;
const EXTREMISM_PROPAGANDA =
  /\b(propoganda\w*|propaganda\w*|argument\w*|slogan\w*|überzeug\w*|rekrutier\w*|beitret\w*|join\w*|manifest\w*|verherrlich\w*|glorifizier\w*|unterstütz\w*|werb\w*)\b/i;

const EXTREMISM_TOPIC = EXTREMISM_GROUP.test(detectText);
const EXTREMISM_ATTEMPT =
  EXTREMISM_GROUP.test(intentText) && EXTREMISM_PROPAGANDA.test(intentText) && !DEFENSIVE_CTX.test(intentText);

add("extremism_propaganda", EXTREMISM_ATTEMPT || (EXTREMISM_TOPIC && EXTREMISM_PROPAGANDA.test(detectText)));

// --- Hate / CSAM ---
const CSAM =
  /\b(kinderporno|kinderpornografie|kinderpornografisch|jugendpornografie|csam|child sexual abuse material|child porn)\b/i;

const HATE_VIOLENCE =
  /\b(töten|umbringen|vernichten|ausrotten|vergase(n)?|abschlachten|kill|murder)\b.*\b(juden|muslime|christen|schwule|lesben|trans|ausländer|flüchtlinge|roma|sinti|jews|muslims|christians|gays|lesbians|trans)\b/i;

add("csam", CSAM.test(detectText));
add("hate_violence", HATE_VIOLENCE.test(detectText));

// --- Cyber / Fraud / Phishing ---
const CYBER =
  /\b(sql[- ]?injection|xss|rce|exploit|payload|malware|ransomware|keylogger|phishing|ddos|botnet)\b/i;

const SQLI_TOKENS =
  /\b(or\s+1\s*=\s*1|union\s+select|--\s|\/\*|\bxp_cmdshell\b)\b/i;

const CYBER_OFFENSIVE =
  /\b(umgehen|bypass|admin[- ]?login|passwort\s+knacken|credential\s+stuffing|exploit|payload|bypass login|evade|steal)\b/i;

const HOWTO =
  /\b(anleitung|schritt[- ]für[- ]schritt|tutorial|how\s*to|guide|walkthrough|rezept|herstellen|synthe(se|sieren)|bauen|konstruier|kochen|mischen|wie\s+(mache|baue|erstelle|create|build|generate))\b/i;

const CYBER_TOPIC = CYBER.test(detectText) || SQLI_TOKENS.test(detectText);

const CYBER_ATTEMPT =
  (CYBER.test(intentText) || SQLI_TOKENS.test(intentText)) &&
  (CYBER_OFFENSIVE.test(intentText) || HOWTO.test(intentText) || SQLI_TOKENS.test(intentText)) &&
  !DEFENSIVE_CTX.test(intentText);

add("cyber_offensive", CYBER_ATTEMPT || CYBER_TOPIC);

// Fraud
const FRAUD =
  /\b(betrug|scam|carding|fake id|ausweis fälschen|kontoübernahme|account takeover|impersonat(e|ion))\b/i;

const FRAUD_DEFENSIVE =
  /\b(woran erkenne|wie erkenne|prüfen|echtheit|was mache ich wenn|was tun wenn|melden|anzeige|how to spot|how to detect|prevention|mitigation)\b/i;

const FRAUD_TOPIC = FRAUD.test(detectText);
const FRAUD_ATTEMPT = FRAUD.test(intentText) && !FRAUD_DEFENSIVE.test(intentText) && !DEFENSIVE_CTX.test(intentText);

add("fraud_offensive", FRAUD_ATTEMPT || FRAUD_TOPIC);

// Phishing (Topic + Attempt)
const PHISHING =
  /\b(phishing|fake\s+login|credential\s+harvest|harvest\s+credentials|spoof|lookalike\s+domain|clone\s+site|brand(ing)?\s+copy|copy(ing)?\s+the\s+brand|gefälscht(e|er)?\s+(mail|e-?mail)|login[- ]?link)\b/i;

const PHISHING_VERB =
  /\b(create|write|generate|draft|build|make|erstell|schreib|verfass|bau)\b/i;

const PHISHING_TOPIC = PHISHING.test(detectText);
const PHISHING_ATTEMPT = PHISHING.test(intentText) && (PHISHING_VERB.test(intentText) || HOWTO.test(intentText)) && !DEFENSIVE_CTX.test(intentText);

add("phishing", PHISHING_ATTEMPT || PHISHING_TOPIC);

// --- PII detection (safer phone) ---
const EMAIL_RE = /[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i;

function extractPhones(text) {
  const candidates = text.match(/(?:\+|00)?\d[\d\s\-()\/]{8,}\d/g) ?? [];
  const phones = [];
  for (const c of candidates) {
    if (/[.:]/.test(c)) continue; // IP/Version
    const digits = (c.match(/\d/g) ?? []).join("");
    if (digits.length < 10 || digits.length > 15) continue;
    const trimmed = c.trim();
    if (!(trimmed.startsWith("+") || trimmed.startsWith("00") || trimmed.startsWith("0"))) continue;
    phones.push(c);
  }
  return phones;
}

const hasEmail = EMAIL_RE.test(fullText);
const phones = extractPhones(fullText);
const hasPhone = phones.length > 0;

add("pii_email", hasEmail);
add("pii_phone", hasPhone);

const hasHowTo = HOWTO.test(intentText);

// --- Routing-Entscheidung ---
// PII -> NICHT ins Output Gate
const nonPIITriggered = triggered.filter(k => !k.startsWith("pii_"));
const piiOnly = nonPIITriggered.length === 0 && (hasEmail || hasPhone);

// Alles “Thema erkannt” -> Output Gate (LLM) übernehmen lassen
const needsLLMGate = nonPIITriggered.length > 0;

// Optional: “hardBlock” nur als Debug/Signal für Output Gate
// (Hier strenger nur bei echten Attempts)
const hardBlock =
  PI_ATTACK ||
  EXFIL_ATTEMPT ||
  nonPIITriggered.includes("csam") ||
  nonPIITriggered.includes("hate_violence") ||
  nonPIITriggered.includes("extremism_propaganda") ||
  CYBER_ATTEMPT ||
  PHISHING_ATTEMPT ||
  FRAUD_ATTEMPT;

// Output shaping
let notice = ($json.notice ?? "").toString();
let outSummary = summary;
let outSources = sources;
let redacted = false;

// PII redaction: direkt Webhook, keine Quellen
if (hasEmail) { outSummary = outSummary.replace(EMAIL_RE, "[REDACTED_EMAIL]"); redacted = true; }
if (hasPhone) { outSummary = outSummary.replace(/(?:\+|00)?\d[\d\s\-()\/]{8,}\d/g, "[REDACTED_PHONE]"); redacted = true; }

if (piiOnly) {
  outSources = [];
  notice = notice || "Ich habe potenziell personenbezogene Daten erkannt und im Output entfernt; Quellen wurden vorsorglich nicht ausgegeben.";
}

// Wenn LLM Gate: lieber keine Snippets (optional), damit Output Gate sauber antwortet.
if (needsLLMGate) {
  // Optional: Summary behalten oder leeren
  outSummary = summary;
  // Snippets weglassen, nur Title+URL durchreichen
  outSources = sources.map(s => ({ title: s.title ?? "", url: s.url ?? "" }));
  notice = notice || "Sicherheitsrelevantes Thema erkannt – wird im Output Gate geprüft.";
}

return [{
  json: {
    ...$json,
    blocked: false, // Flow soll weiterlaufen
    notice,
    summary: outSummary,
    sources: outSources,
    fastGate: {
      triggered,
      hasHowTo,
      hardBlock,
      softFlag: nonPIITriggered.length > 0 || redacted,
      needsLLMGate,
      // extra debug (kannst du später entfernen)
      debug: {
        piiOnly,
        nonPIITriggered,
        PI_TOPIC,
        PI_ATTACK,
        EXFIL_TOPIC,
        EXFIL_ATTEMPT,
        CYBER_TOPIC,
        CYBER_ATTEMPT,
        PHISHING_TOPIC,
        PHISHING_ATTEMPT,
        FRAUD_TOPIC,
        FRAUD_ATTEMPT
      }
    }
  }
}];

// Deterministic snippet summarizer (no LLM)
// Expects: query/searchQuery + results/sources array with {title,url,snippet|content}
// Returns: { summary, sources } merged into existing item

function stripHtml(s) {
  return (s || "")
    .replace(/<script[\s\S]*?>[\s\S]*?<\/script>/gi, " ")
    .replace(/<style[\s\S]*?>[\s\S]*?<\/style>/gi, " ")
    .replace(/<[^>]+>/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function decodeEntities(s) {
  return (s || "")
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'");
}

function safeText(s, maxLen = 1100) {
  const t = decodeEntities(stripHtml(s)).trim();
  if (!t) return "";
  return t.length > maxLen ? t.slice(0, maxLen - 1) + "…" : t;
}

function hostOf(url) {
  try {
    const u = new URL(url);
    return u.hostname.replace(/^www\./, "");
  } catch {
    return "";
  }
}

function tokenizeDE(text) {
  const stop = new Set([
    "der","die","das","den","dem","des","ein","eine","einer","einem","einen",
    "und","oder","aber","zu","zum","zur","von","im","in","am","an","auf","für",
    "mit","ohne","um","bei","über","unter","nach","vor","hinter","zwischen",
    "ich","du","er","sie","es","wir","ihr","mir","mich","dir","dich","uns","euch",
    "bitte","mal","noch","auch","nur","sehr","mehr","weniger",
    "was","wer","wie","wo","wann","warum","wieso","weshalb","welche","welcher","welches",
    "gibt","geben","ist","sind","war","waren","sein","habe","hast","hat","haben",
    "infos","info","information","informationen","details","detail",
    "suche","suchen","finde","finden"
  ]);
  const toks = (text || "").toLowerCase().match(/[a-zäöüß0-9]{2,}/g) ?? [];
  return toks.filter(t => t.length >= 3 && !stop.has(t));
}

function redactPII(s) {
  const EMAIL_RE = /[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/ig;
  const PHONE_RE = /(?:\+|00)?\d[\d\s\-()\/]{8,}\d/g;
  let out = s || "";
  out = out.replace(EMAIL_RE, "[REDACTED_EMAIL]");
  out = out.replace(PHONE_RE, (m) => {
    if (/[.:]/.test(m)) return m; // avoid IP/Version
    const digits = (m.match(/\d/g) ?? []).join("");
    if (digits.length < 10 || digits.length > 15) return m;
    return "[REDACTED_PHONE]";
  });
  return out;
}

// Take first item (workflow typically works with 1 item)
const item = $input.first().json;

const query = (item.searchQuery ?? item.query ?? "").toString().trim();

// Support different shapes: results OR sources OR data.results
const rawArr =
  (Array.isArray(item.results) && item.results) ||
  (Array.isArray(item.sources) && item.sources) ||
  (Array.isArray(item.data?.results) && item.data.results) ||
  [];

// Normalize sources
const normalized = rawArr
  .map((r, idx) => {
    const url = (r.url ?? r.link ?? "").toString();
    const title = safeText(r.title ?? r.name ?? "", 140);

    // 👇 Snippet-Länge hier zentral steuerbar
    const snippetMax = Number(item.snippetMaxLen ?? 1100);
    const snippet = safeText(r.snippet ?? r.content ?? r.description ?? "", isFinite(snippetMax) ? snippetMax : 1100);

    const host = hostOf(url);
    return {
      id: idx + 1,
      title,
      url,
      host,
      snippet: redactPII(snippet),
      _raw: r
    };
  })
  .filter(s => s.url || s.title || s.snippet);

// Dedupe by url/host+title
const seen = new Set();
const deduped = [];
for (const s of normalized) {
  const key = (s.url || (s.host + "|" + s.title)).toLowerCase();
  if (seen.has(key)) continue;
  seen.add(key);
  deduped.push(s);
}

// Rank by keyword overlap with query
const qTokens = tokenizeDE(query);
const qSet = new Set(qTokens);
function scoreSource(s) {
  const t = tokenizeDE(`${s.title} ${s.snippet}`);
  let overlap = 0;
  for (const tok of t) if (qSet.has(tok)) overlap++;
  const hostBonus = s.host ? 0.2 : 0;
  const titleBonus = s.title ? 0.2 : 0;
  return overlap + hostBonus + titleBonus;
}

const ranked = deduped
  .map(s => ({ ...s, _score: scoreSource(s) }))
  .sort((a, b) => b._score - a._score);

// pick top N sources for summary + return list
const maxSources = Number(item.maxSourcesInSummary ?? 10);
const MAX_SOURCES = Math.min(isFinite(maxSources) ? maxSources : 10, ranked.length);
const top = ranked.slice(0, MAX_SOURCES);

// Build extractive “key points” (1 point per source)
function firstGoodSentence(text) {
  const cleaned = (text || "").replace(/\s+/g, " ").trim();
  if (!cleaned) return "";

  // ✅ kompatibel ohne Lookbehind:
  const parts = cleaned.split(/[.!?]\s+/);

  const bulletMax = Number(item.bulletMaxLen ?? 360);
  const max = isFinite(bulletMax) ? bulletMax : 360;

  for (const p of parts) {
    const pp = (p || "").trim();
    if (pp.length >= 40) {
      return pp.length > max ? pp.slice(0, max - 1) + "…" : pp;
    }
  }

  // fallback: truncate whole snippet
  return cleaned.length > max ? cleaned.slice(0, max - 1) + "…" : cleaned;
}

// Guard against snippet prompt-injection / instructions in snippets
const INJECTION_LINE =
  /\b(ignorier(e|en)?|systemprompt|developer message|rolle:\s*system|jailbreak|do anything now|prompt[- ]injection)\b/i;

const bullets = [];
for (const s of top) {
  const sentence = firstGoodSentence(s.snippet);
  if (!sentence) continue;
  if (INJECTION_LINE.test(sentence)) continue;
  bullets.push(`- ${sentence} [${s.id}]`);
}

// Final summary
let summary = "";
if (bullets.length === 0) {
  summary = `Keine brauchbaren Snippets gefunden. Bitte präzisiere die Anfrage oder erhöhe maxResults.`;
} else {
  summary =
    `**Kurz-Zusammenfassung (aus Snippets, untrusted):**\n` +
    bullets.join("\n");
}

// Return sources in expected structure
const outSources = top.map(s => ({
  id: s.id,
  title: s.title,
  url: s.url,
  snippet: s.snippet
}));

return [{
  json: {
    ...item,
    summary,
    sources: outSources
  }
}];

const item = $input.first().json;

const requested = Number(item.maxResults ?? 5);
const maxResultsClamped = Math.max(1, Math.min(10, isFinite(requested) ? requested : 5)); // <-- HIER clamp anpassen (z.B. 8/10/12)

// Kontext-Limits (HIER einstellen)
const snippetMaxLen = 1100;       // wie lang jedes Source-Snippet sein darf
const bulletMaxLen = 360;         // wie lang ein Bullet in der Summary sein darf
const maxSourcesInSummary = 10;   // wie viele Quellen in Summary/Sources durchgehen

return [{
  json: {
    ...item,
    maxResultsClamped,
    snippetMaxLen,
    bulletMaxLen,
    maxSourcesInSummary,
  }
}];
